// Base API client configuration
import {
  clearAuthTokens,
  clearAuthUser,
  getAuthRefreshToken,
  getAuthToken,
  getAuthUser,
  resolveAuthRefreshUrl,
  setAuthTokens,
  setAuthUser,
} from '@linm-soft/common-components';
import type { User } from '../models/User';

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5010/web-bff/api/v1';

export interface ApiError {
  message: string;
  statusCode: number;
  errors?: Record<string, string[]>;
}

// ── Token-refresh state (module-level singletons) ───────────────────────────
let refreshPromise: Promise<boolean> | null = null;

/**
 * Optional callback invoked after a successful silent token refresh.
 * Register this from App.tsx / authSlice so the Redux store can be updated
 * when new user data (e.g. defaultMenuUrl) arrives with the refreshed token.
 */
type RefreshSuccessCallback = (rawResponse: Record<string, unknown>) => void;
let _onRefreshSuccess: RefreshSuccessCallback | null = null;

/** Register a callback that is called after every successful silent token refresh. */
export function registerRefreshSuccessCallback(cb: RefreshSuccessCallback): void {
  _onRefreshSuccess = cb;
}

/**
 * Attempt to obtain a new access token using the stored refresh token.
 * De-duplicates concurrent calls so only one refresh request is in-flight.
 * Returns `true` if refresh succeeded (new tokens already saved to localStorage).
 * When user data changes (e.g. defaultMenuUrl), the registered callback is invoked.
 */
function tryRefreshToken(): Promise<boolean> {
  if (refreshPromise) return refreshPromise;

  refreshPromise = (async () => {
    const rt = getAuthRefreshToken();
    if (!rt) return false;

    try {
      const res = await fetch(resolveAuthRefreshUrl(), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken: rt }),
      });

      if (!res.ok) return false;

      const data = await res.json();
      setAuthTokens({
        accessToken: data.token ?? undefined,
        refreshToken: data.refreshToken ?? undefined,
      });

      // Persist updated user data and notify the store so UI reflects any changes
      // (e.g. admin changed the user's defaultMenuUrl between sessions)
      if (data.user) {
        const prev = getAuthUser();
        const nextUser = data.user as User;
        if (JSON.stringify(prev) !== JSON.stringify(nextUser)) {
          setAuthUser(nextUser);
          _onRefreshSuccess?.(data);
        }
      }

      return true;
    } catch {
      return false;
    } finally {
      refreshPromise = null;
    }
  })();

  return refreshPromise;
}

/** Clear all auth data and redirect to /login respecting the Vite base path. */
function redirectToLogin(): void {
  clearAuthTokens();
  clearAuthUser();
  const base = import.meta.env.BASE_URL || '/';
  window.location.href = `${base}login`;
}

class ApiClient {
  private baseURL: string;

  constructor(baseURL: string) {
    this.baseURL = baseURL;
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const url = `${this.baseURL}${endpoint}`;
    
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      // Carry the client's IANA timezone on every request so the BFF can
      // resolve the local date for IdCode generation (X-Timezone contract).
      'X-Timezone': Intl.DateTimeFormat().resolvedOptions().timeZone,
      ...(options.headers as Record<string, string>),
    };

    // Inject JWT token from localStorage
    const token = getAuthToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    try {
      const response = await fetch(url, {
        ...options,
        headers,
      });

      if (!response.ok) {
        // ── 401 Handling ──────────────────────────────────────────────────
        // Skip auto-refresh for auth endpoints themselves (login/logout/refresh)
        // to avoid infinite loops and to let wrong-credential errors surface.
        if (response.status === 401) {
          const isAuthSelfEndpoint =
            endpoint.includes('/auth/login') ||
            endpoint.includes('/auth/logout') ||
            endpoint.includes('/auth/refresh-token');

          if (!isAuthSelfEndpoint) {
            // Try silent token refresh
            const refreshed = await tryRefreshToken();

            if (refreshed) {
              // Retry the original request with the new access token
              const newToken = getAuthToken();
              if (newToken) {
                headers['Authorization'] = `Bearer ${newToken}`;
              }
              const retryResponse = await fetch(url, { ...options, headers });

              if (retryResponse.ok) {
                if (retryResponse.status === 204) return undefined as unknown as T;
                return await retryResponse.json();
              }
            }

            // Refresh failed or retry still 401 → redirect to login
            redirectToLogin();
            throw new Error('Phiên đăng nhập hết hạn. Vui lòng đăng nhập lại.');
          }
        }

        let errorMessage = 'API request failed';
        try {
          const errorBody = await response.json();
          errorMessage =
            errorBody?.error?.toastMessage ||
            errorBody?.message ||
            errorBody?.title ||
            errorMessage;
        } catch {
          // ignore JSON parse errors on error body
        }
        throw new Error(errorMessage);
      }

      // 204 No Content
      if (response.status === 204) {
        return undefined as unknown as T;
      }

      return await response.json();
    } catch (error) {
      // Suppress noisy logs for network/connection errors (e.g. backend not running)
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        console.warn('[API] Network error — server may be unavailable:', endpoint);
      } else {
        console.error('API request error:', error);
      }
      throw error;
    }
  }

  async get<T>(endpoint: string): Promise<T> {
    return this.request<T>(endpoint, { method: 'GET' });
  }

  async post<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'POST',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async put<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'PUT',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async patch<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'PATCH',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async delete<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'DELETE',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  /**
   * POST JSON body and receive a binary file (Blob) response.
   * Used for backend-generated file exports (Excel, PDF, etc.).
   */
  async postBlob(endpoint: string, data?: unknown): Promise<Blob> {
    const url = `${this.baseURL}${endpoint}`;
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'X-Timezone': Intl.DateTimeFormat().resolvedOptions().timeZone,
    };
    const token = getAuthToken();
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await fetch(url, {
      method: 'POST',
      headers,
      body: data ? JSON.stringify(data) : undefined,
    });

    if (!response.ok) {
      let errorMessage = 'Export thất bại';
      try {
        const errorBody = await response.json();
        errorMessage = errorBody?.error?.toastMessage || errorBody?.message || errorMessage;
      } catch { /* ignore */ }
      throw new Error(errorMessage);
    }

    return response.blob();
  }
}

export const apiClient = new ApiClient(API_BASE_URL);
