import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface UIState {
  toasts: Array<{
    id: string;
    message: string;
    type: 'success' | 'error' | 'warning' | 'info';
  }>;
  silentMode: boolean;
}

const initialState: UIState = {
  toasts: [],
  silentMode: localStorage.getItem('notification-silent-mode') === 'true',
};

const uiSlice = createSlice({
  name: 'ui',
  initialState,
  reducers: {
    addToast: (state, action: PayloadAction<Omit<UIState['toasts'][0], 'id'>>) => {
      state.toasts.push({
        id: Date.now().toString(),
        ...action.payload,
      });
    },
    removeToast: (state, action: PayloadAction<string>) => {
      state.toasts = state.toasts.filter((toast) => toast.id !== action.payload);
    },
    clearToasts: (state) => {
      state.toasts = [];
    },
    toggleSilentMode: (state) => {
      state.silentMode = !state.silentMode;
      localStorage.setItem('notification-silent-mode', String(state.silentMode));
    },
  },
});

export const {
  addToast,
  removeToast,
  clearToasts,
  toggleSilentMode,
} = uiSlice.actions;

export default uiSlice.reducer;
